const a = msg.payload || {};

const tsRaw = a.timestamp || a.ais?.time_stamp || a.served_at || null;

const ts = tsRaw
  ? new Date(tsRaw).toLocaleString("nb-NO", {
      timeZone: "Europe/Oslo",
      year: "numeric",
      month: "2-digit",
      day: "2-digit",
      hour: "2-digit",
      minute: "2-digit"
    })
  : "ukjent";

const vesselName = a.name || "Ukjent fartøy";
const statusText = a.raw_status || a.status || "Ukjent status";
const station = a.station || "Ukjent stasjon";
const region = a.station_region ? ` (${a.station_region})` : "";
const details = `RS: ${a.rs || "-"} • MMSI: ${a.mmsi || "-"} • Callsign: ${a.callsign || "-"}`;
const staleNote = a.stale ? "\n⚠️ Data kan være forsinket." : "";

msg.payload = {
  title: vesselName,
  message: `${statusText}\nStasjon: ${station}${region}\n${details}\nSist oppdatert: ${ts}${staleNote}`,
  data: {
    image: a.image_url || undefined,
    clickAction: "entityId:sensor.rs_vessel_status",
    tag: "rs_vessel_status",
    group: "rs_status"
  }
};

return msg;
